 1→import { headers } from "next/headers";
 2→import { cache } from "react";
 3→import type { z } from "zod";
 4→import { auth } from "@/lib/auth";
 5→
 6→/** Deduplicated per request via React cache() */
 7→export const getAuthedSession = cache(async () => {
 8→  const session = await auth.api.getSession({ headers: await headers() });
 9→  if (!session) throw new Error("Unauthorized");
10→  return session;
11→});
12→
13→/** Validate input against a Zod schema or throw */
14→export function parseInput<T extends z.ZodType>(
15→  schema: T,
16→  raw: unknown,
17→): z.infer<T> {
18→  const result = schema.safeParse(raw);
19→  if (!result.success) {
20→    throw new Error(result.error.issues.map((i) => i.message).join(", "));
21→  }
22→  return result.data;
23→}
24→
25→type AuthContext = Awaited<ReturnType<typeof getAuthedSession>>;
26→
27→/** Create an authed action with optional Zod validation */
28→export function authedAction<TOutput>(
29→  handler: (ctx: AuthContext) => Promise<TOutput>,
30→): () => Promise<TOutput>;
31→export function authedAction<TInput, TOutput>(
32→  schema: z.ZodType<TInput>,
33→  handler: (ctx: AuthContext, input: TInput) => Promise<TOutput>,
34→): (raw: unknown) => Promise<TOutput>;
35→export function authedAction<TInput, TOutput>(
36→  schemaOrHandler: z.ZodType<TInput> | ((ctx: AuthContext) => Promise<TOutput>),
37→  maybeHandler?: (ctx: AuthContext, input: TInput) => Promise<TOutput>,
38→) {
39→  // No schema — just auth
40→  if (typeof schemaOrHandler === "function") {
41→    return async () => {
42→      const session = await getAuthedSession();
43→      return schemaOrHandler(session);
44→    };
45→  }
46→
47→  // Schema + auth
48→  const handler = maybeHandler as (
49→    ctx: AuthContext,
50→    input: TInput,
51→  ) => Promise<TOutput>;
52→  return async (raw: unknown) => {
53→    const session = await getAuthedSession();
54→    const input = parseInput(schemaOrHandler, raw);
55→    return handler(session, input);
56→  };
57→}
